package main

import (
    "fmt"
    "os"
    _ "net/http/pprof"  // Import for side effects
)

func main() {
    // ---- Ignoring return values ----
    _, err := os.Create("test.txt")
    if err != nil {
        fmt.Println("Error:", err)
    }

    // ---- Ignoring index in range ----
    items := []string{"Sword", "Shield", "Potion"}
    for _, item := range items {
        fmt.Println("Item:", item)
    }

    // ---- Ignoring value in range ----
    for i, _ := range items {
        fmt.Println("Index:", i)
    }

    // ---- Ignoring map value ----
    scores := map[string]int{"Hero": 100, "Aragorn": 85}
    for name, _ := range scores {
        fmt.Println("Name:", name)
    }

    // ---- Ignoring map key ----
    for _, score := range scores {
        fmt.Println("Score:", score)
    }

    // ---- Check if key exists ----
    _, ok := scores["Legolas"]
    if !ok {
        fmt.Println("Legolas not found")
    }

    // ---- Ignoring error when you're sure it's safe ----
    // This is dangerous! Don't do this casually.
    // _ = someFunctionThatReturnsError()

    // ---- Blank identifier in type assertions ----
    var i interface{} = 42
    _, ok := i.(string)
    if !ok {
        fmt.Println("Not a string")
    }

    // ---- Blank identifier for imports ----
    // import _ "net/http/pprof"
    // This imports the package for its side effects

    fmt.Println("Done!")
}

