phase3.solution:
package main

import "fmt"

func main() {
    fruits := []string{"Apple", "Banana", "Orange"}
    for _, fruit := range fruits {
        fmt.Println(fruit)
    }

    scores := map[string]int{"Hero": 100, "Aragorn": 85}
    for name, _ := range scores {
        fmt.Println(name)
    }

    _, ok := scores["Gandalf"]
    if !ok {
        fmt.Println("Gandalf not found")
    }
}
